patch:
 drivers/media/IR/imon.c |   68 ++++++++++++++++++++++++++++++++++++----------
 1 files changed, 53 insertions(+), 15 deletions(-)

diff --git a/drivers/media/IR/imon.c b/drivers/media/IR/imon.c
index 433dca6..5fb3638 100644
--- a/drivers/media/IR/imon.c
+++ b/drivers/media/IR/imon.c
@@ -124,6 +124,7 @@ struct imon_context {
 	struct input_dev *idev;		/* input device for remote */
 	struct input_dev *touch;	/* input device for touchscreen */

+	spinlock_t kc_lock;		/* make sure we get keycodes right */
 	u32 kc;				/* current input keycode */
 	u32 last_keycode;		/* last reported input keycode */
 	u64 ir_type;			/* iMON or MCE (RC6) IR protocol? */
@@ -956,13 +957,20 @@ static void usb_tx_callback(struct urb *urb)
 }

 /**
- * mce/rc6 keypresses have no distinct release code, use timer
+ * Used for keypresses w/o a distinct release code, and to ensure
+ * we don't get stuck keys if a release code is missed.
  */
-static void imon_mce_timeout(unsigned long data)
+static void imon_input_timeout(unsigned long data)
 {
 	struct imon_context *ictx = (struct imon_context *)data;
+	unsigned long flags;
+	u32 kc;
+
+	spin_lock_irqsave(&ictx->kc_lock, flags);
+	kc = ictx->last_keycode;
+	spin_unlock_irqrestore(&ictx->kc_lock, flags);

-	input_report_key(ictx->idev, ictx->last_keycode, 0);
+	input_report_key(ictx->idev, kc, 0);
 	input_sync(ictx->idev);
 }

@@ -1006,9 +1014,6 @@ int imon_ir_change_protocol(void *priv, u64 ir_type)
 		dev_dbg(dev, "Configuring IR receiver for MCE protocol\n");
 		ir_proto_packet[0] = 0x01;
 		pad_mouse = false;
-		init_timer(&ictx->itimer);
-		ictx->itimer.data = (unsigned long)ictx;
-		ictx->itimer.function = imon_mce_timeout;
 		break;
 	case IR_TYPE_UNKNOWN:
 	case IR_TYPE_OTHER:
@@ -1191,6 +1196,9 @@ static u32 imon_mce_key_lookup(struct imon_context *ictx, u32 hw_code)

 	keycode = ir_g_keycode_from_table(ictx->idev, scancode);

+	/* not used in mce mode, but make sure we know its false */
+	ictx->release_code = false;
+
 	return keycode;
 }

@@ -1217,6 +1225,7 @@ static bool imon_mouse_event(struct imon_context *ictx,
 	u8 right_shift = 1;
 	bool mouse_input = true;
 	int dir = 0;
+	unsigned long flags;

 	/* newer iMON device PAD or mouse button */
 	if (ictx->product != 0xffdc && (buf[0] & 0x01) && len == 5) {
@@ -1262,7 +1271,9 @@ static bool imon_mouse_event(struct imon_context *ictx,
 					 buf[1] >> right_shift & 0x1);
 		}
 		input_sync(ictx->idev);
+		spin_lock_irqsave(&ictx->kc_lock, flags);
 		ictx->last_keycode = ictx->kc;
+		spin_unlock_irqrestore(&ictx->kc_lock, flags);
 	}

 	return mouse_input;
@@ -1391,9 +1402,10 @@ static int imon_parse_press_type(struct imon_context *ictx,
 				 unsigned char *buf, u8 ktype)
 {
 	int press_type = 0;
-	int rep_delay = ictx->idev->rep[REP_DELAY];
-	int rep_period = ictx->idev->rep[REP_PERIOD];
+	int delay = ictx->idev->rep[REP_DELAY];
+	unsigned long flags;

+	spin_lock_irqsave(&ictx->kc_lock, flags);
 	/* key release of 0x02XXXXXX key */
 	if (ictx->kc == KEY_RESERVED && buf[0] == 0x02 && buf[3] == 0x00)
 		ictx->kc = ictx->last_keycode;
@@ -1416,13 +1428,10 @@ static int imon_parse_press_type(struct imon_context *ictx,
 			ictx->last_keycode = ictx->kc;
 			ictx->mce_toggle_bit = buf[2];
 			press_type = 1;
-			mod_timer(&ictx->itimer,
-				  jiffies + msecs_to_jiffies(rep_delay));
 		/* repeat */
 		} else {
 			press_type = 2;
-			mod_timer(&ictx->itimer,
-				  jiffies + msecs_to_jiffies(rep_period));
+			delay = ictx->idev->rep[REP_PERIOD];
 		}

 	/* incoherent or irrelevant data */
@@ -1437,6 +1446,11 @@ static int imon_parse_press_type(struct imon_context *ictx,
 	else
 		press_type = 1;

+	spin_unlock_irqrestore(&ictx->kc_lock, flags);
+
+	if (press_type > 0)
+		mod_timer(&ictx->itimer, jiffies + msecs_to_jiffies(delay));
+
 	return press_type;
 }

@@ -1451,6 +1465,8 @@ static void imon_incoming_packet(struct imon_context *ictx,
 	struct device *dev = ictx->dev;
 	u32 kc;
 	bool norelease = false;
+	bool newkey = false;
+	u32 oldkc;
 	int i;
 	u64 temp_key;
 	u64 panel_key = 0;
@@ -1461,6 +1477,7 @@ static void imon_incoming_packet(struct imon_context *ictx,
 	struct timeval t;
 	static struct timeval prev_time = { 0, 0 };
 	u8 ktype = IMON_KEY_IMON;
+	unsigned long flags;

 	idev = ictx->idev;

@@ -1484,6 +1501,7 @@ static void imon_incoming_packet(struct imon_context *ictx,
 			kc = imon_remote_key_lookup(ictx, remote_key);
 	}

+	spin_lock_irqsave(&ictx->kc_lock, flags);
 	/* keyboard/mouse mode toggle button */
 	if (kc == KEY_KEYBOARD && !ictx->release_code) {
 		ictx->last_keycode = kc;
@@ -1491,6 +1509,7 @@ static void imon_incoming_packet(struct imon_context *ictx,
 			ictx->pad_mouse = ~(ictx->pad_mouse) & 0x1;
 			dev_dbg(dev, "toggling to %s mode\n",
 				ictx->pad_mouse ? "mouse" : "keyboard");
+			spin_unlock_irqrestore(&ictx->kc_lock, flags);
 			return;
 		} else {
 			ictx->pad_mouse = 0;
@@ -1499,6 +1518,11 @@ static void imon_incoming_packet(struct imon_context *ictx,
 	}

 	ictx->kc = kc;
+	oldkc = ictx->last_keycode;
+	spin_unlock_irqrestore(&ictx->kc_lock, flags);
+
+	if (ictx->kc != oldkc)
+		newkey = true;

 	/* send touchscreen events through input subsystem if touchpad data */
 	if (ictx->display_type == IMON_DISPLAY_TYPE_VGA && len == 8 &&
@@ -1534,15 +1558,24 @@ static void imon_incoming_packet(struct imon_context *ictx,
 	if (ictx->kc == KEY_UNKNOWN)
 		goto unknown_key;

+	if (newkey && press_type != 0) {
+		input_report_key(idev, oldkc, 0);
+		input_sync(idev);
+	}
+
+	spin_lock_irqsave(&ictx->kc_lock, flags);
 	/* KEY_MUTE repeats from MCE and knob need to be suppressed */
 	if ((ictx->kc == KEY_MUTE && ictx->kc == ictx->last_keycode)
 	    && (buf[7] == 0xee || ktype == IMON_KEY_MCE)) {
 		do_gettimeofday(&t);
 		msec = tv2int(&t, &prev_time);
 		prev_time = t;
-		if (msec < idev->rep[REP_DELAY])
+		if (msec < idev->rep[REP_DELAY]) {
+			spin_unlock_irqrestore(&ictx->kc_lock, flags);
 			return;
+		}
 	}
+	spin_unlock_irqrestore(&ictx->kc_lock, flags);

 	input_report_key(idev, ictx->kc, press_type);
 	input_sync(idev);
@@ -1553,7 +1586,9 @@ static void imon_incoming_packet(struct imon_context *ictx,
 		input_sync(idev);
 	}

+	spin_lock_irqsave(&ictx->kc_lock, flags);
 	ictx->last_keycode = ictx->kc;
+	spin_unlock_irqrestore(&ictx->kc_lock, flags);

 	return;

@@ -1886,6 +1921,10 @@ static struct imon_context *imon_init_intf0(struct usb_interface *intf)
 	}

 	mutex_init(&ictx->lock);
+	spin_lock_init(&ictx->kc_lock);
+	init_timer(&ictx->itimer);
+	ictx->itimer.data = (unsigned long)ictx;
+	ictx->itimer.function = imon_input_timeout;

 	mutex_lock(&ictx->lock);

@@ -2310,8 +2349,7 @@ static void __devexit imon_disconnect(struct usb_interface *interface)
 		if (!ictx->display_isopen)
 			free_imon_context(ictx);
 	} else {
-		if (ictx->ir_type == IR_TYPE_RC6)
-			del_timer_sync(&ictx->itimer);
+		del_timer_sync(&ictx->itimer);
 		mutex_unlock(&ictx->lock);
 	}
